-- [ ObfusPro+ ]
local DUiJk = bit32 or bit or error("ObfusPro+: Environment error");
local function zOWzBE(XMinT)
    local vNaYlBpu = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
    local tOGMB = string.gsub(XMinT, '[^' .. vNaYlBpu .. ']', '')
    local NAXAAUY = {}
    for rRMK = 1, #tOGMB, 4 do
        local asE, bCy, yiU, feZ = string.byte(tOGMB, rRMK, rRMK + 3)
        if not asE then break end
        local LqTr = string.find(vNaYlBpu, string.char(asE)) - 1
        local jrwP = string.find(vNaYlBpu, string.char(bCy)) - 1
        local zHum = yiU and string.find(vNaYlBpu, string.char(yiU)) - 1 or 0
        local UJaO = feZ and string.find(vNaYlBpu, string.char(feZ)) - 1 or 0
        local vmue = LqTr * 262144 + jrwP * 4096 + zHum * 64 + UJaO
        local Ldyk = DUiJk.band(DUiJk.rshift(vmue, 16), 255)
        table.insert(NAXAAUY, string.char(DUiJk.bxor(Ldyk, 50)))
        if yiU and string.char(yiU) ~= '=' then
            Ldyk = DUiJk.band(DUiJk.rshift(vmue, 8), 255)
            table.insert(NAXAAUY, string.char(DUiJk.bxor(Ldyk, 50)))
        end
        if feZ and string.char(feZ) ~= '=' then
            Ldyk = DUiJk.band(vmue, 255)
            table.insert(NAXAAUY, string.char(DUiJk.bxor(Ldyk, 50)))
        end
    end
    return table.concat(NAXAAUY)
end
